package com.socialblog.comment.api;import jakarta.servlet.http.HttpServletRequest;import org.springframework.http.*;import org.springframework.web.bind.MethodArgumentNotValidException;import org.springframework.web.bind.annotation.*;import java.time.Instant;import java.util.*;
@RestControllerAdvice public class GlobalExceptionHandler{public record Error(Instant timestamp,int status,String code,String message,String path,Map<String,String>fields){}@ExceptionHandler(ApiException.class)ResponseEntity<Error>api(ApiException e,HttpServletRequest r){return ResponseEntity.status(e.status()).body(new Error(Instant.now(),e.status().value(),e.code(),e.getMessage(),r.getRequestURI(),Map.of()));}@ExceptionHandler(MethodArgumentNotValidException.class)ResponseEntity<Error>valid(MethodArgumentNotValidException e,HttpServletRequest r){Map<String,String>f=new LinkedHashMap<>();e.getBindingResult().getFieldErrors().forEach(x->f.putIfAbsent(x.getField(),x.getDefaultMessage()));return ResponseEntity.badRequest().body(new Error(Instant.now(),400,"VALIDATION_FAILED","Request validation failed",r.getRequestURI(),f));}}
